Actionscript.script:
stop();

import flash.events.MouseEvent;
import flash.display.Shape;
import flash.display.MovieClip;
import flash.utils.Timer;
import flash.events.TimerEvent;

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

// Variabel Global
var skorTotalGame:int = 0;
var gameSelesai:Boolean = false;
var startX:Number;
var startY:Number;
var activeBlock:MovieClip;
var activeIndex:int;
var levelCTD:int = 1;
var sisaWaktu:int = 45; // Ubah angka ini untuk mengatur durasi (dalam detik)
var timerGame:Timer = new Timer(1000); // 1000 milidetik = 1 detak per detik
var isTimerBerjalan:Boolean = false;

// --- FUNGSI TIMER ---
function jalankanTimer():void {
    // Agar timer tidak tergandakan saat pindah frame
    if (!isTimerBerjalan) {
        timerGame.addEventListener(TimerEvent.TIMER, hitungMundur);
        timerGame.start();
        isTimerBerjalan = true;
    }
    updateTeksTimer();
}

function hitungMundur(e:TimerEvent):void {
    sisaWaktu--;
    updateTeksTimer();

    // Apa yang terjadi jika waktu habis (Mencapai 0)
    if (sisaWaktu <= 0) {
        timerGame.stop();
        timerGame.removeEventListener(TimerEvent.TIMER, hitungMundur);

        trace("WAKTU HABIS!");
        // PAKSA PINDAH SCENE! 
        // Jika kode ini di CTD, ganti "Skor" menjadi "DTB"
        gotoAndStop(1, "Skor"); 
    }
}

function updateTeksTimer():void {
    // Matematika untuk memecah detik menjadi format Menit & Detik
    var menit:int = Math.floor(sisaWaktu / 60);
    var detik:int = sisaWaktu % 60;

    // Tambahkan angka 0 di depan jika di bawah 10 (contoh: 09, 08)
    var teksMenit:String = (menit < 10) ? "0" + menit : String(menit);
    var teksDetik:String = (detik < 10) ? "0" + detik : String(detik);

    // Masukkan ke UI teks milikmu (menggunakan titik sesuai desainmu)
    txt_timer.text = teksMenit + "." + teksDetik;
}

// 1. Membuat Wadah Garis
var lines:Array = [];
var indexGaris:int;

for (indexGaris = 1; indexGaris <= 4; indexGaris++) {
    var line:Shape = new Shape();
    addChild(line);
    lines[indexGaris] = line;
}

// 2. KAMUS JAWABAN UNTUK 5 LEVEL
// Index 0 dikosongkan agar Index 1 = Frame 1, Index 2 = Frame 2, dst.
var semuaKunci:Array = [
    null,

    // LEVEL 1 (Frame 1): Tipe Data
    // int(Kanan 4), bool(Kanan 3), string(Kanan 1), double(Kanan 2)
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan2" },

    // LEVEL 2 (Frame 2): Sintaks Dasar C++
    // ;(Kanan 4), { }(Kanan 1), Case-sensitive(Kanan 3), cout(Kanan 2)
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan1", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan2" },

    // LEVEL 3 (Frame 3): Statement Seleksi
    // if(Kanan 1), if...else(Kanan 2), switch(Kanan 3), break(Kanan 4)
    { "btnkiri1":"btnkanan1", "btnkiri2":"btnkanan2", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan4" },

    // LEVEL 4 (Frame 4): Statement Perulangan
    // for loop(Kanan 4), while(Kanan 3), do...while(Kanan 2), off-by-one(Kanan 1)
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan2", "btnkiri4":"btnkanan1" },

    // LEVEL 5 (Frame 5): Error & Konsep Tambahan
    // Sintaksis(Kanan 2), Logika(Kanan 4), 0(Kanan 1), return 0;(Kanan 3)
    { "btnkiri1":"btnkanan2", "btnkiri2":"btnkanan4", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan3" }
];

// 3. FUNGSI SETUP LEVEL (Dijalankan setiap pindah frame)
function setupLevel():void {
    gameSelesai = false;
    jalankanTimer();

    // Tembakkan skor tersimpan ke instance text UI
    txt_poinangka.text = String(skorTotalGame); 

    for (var j:int = 1; j <= 4; j++) {
        lines[j].graphics.clear(); 

        var btn:MovieClip = this["btnkiri" + j] as MovieClip;
        if (btn != null) {
            btn.buttonMode = true;
            btn.index = j;
            btn.connectedTo = null; 

            btn.removeEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
            btn.addEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
        }
    }

    btn_lanjutctd.removeEventListener(MouseEvent.CLICK, onLanjutClick);
    btn_lanjutctd.addEventListener(MouseEvent.CLICK, onLanjutClick);
}

// 4. LOGIKA DRAG & DROP
function onDragStart(e:MouseEvent):void {
    if (gameSelesai) return; 
    activeBlock = e.currentTarget as MovieClip;
    activeIndex = activeBlock.index;
    startX = activeBlock.x + activeBlock.width;
    startY = activeBlock.y + (activeBlock.height / 2);

    stage.addEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.addEventListener(MouseEvent.MOUSE_UP, onDragDrop);
}

function onDragging(e:MouseEvent):void {
    var currentLine:Shape = lines[activeIndex];
    currentLine.graphics.clear();
    currentLine.graphics.lineStyle(5, 0x3399FF); // Garis ditarik (Biru Muda)
    currentLine.graphics.moveTo(startX, startY);
    currentLine.graphics.lineTo(mouseX, mouseY);
}

function onDragDrop(e:MouseEvent):void {
    stage.removeEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.removeEventListener(MouseEvent.MOUSE_UP, onDragDrop);

    var currentLine:Shape = lines[activeIndex];
    var isConnected:Boolean = false;

    for (var k:int = 1; k <= 4; k++) {
        var targetBtn:MovieClip = this["btnkanan" + k] as MovieClip;
        if (targetBtn.hitTestPoint(mouseX, mouseY, true)) {
            var targetX:Number = targetBtn.x; 
            var targetY:Number = targetBtn.y + (targetBtn.height / 2);

            currentLine.graphics.clear();
            currentLine.graphics.lineStyle(5, 0x297ACC); // Garis nempel (Biru Tua)
            currentLine.graphics.moveTo(startX, startY);
            currentLine.graphics.lineTo(targetX, targetY);

            activeBlock.connectedTo = targetBtn.name;
            isConnected = true;
            break; 
        }
    }
    if (!isConnected) {
        currentLine.graphics.clear();
        activeBlock.connectedTo = null;
    }
}

function onLanjutClick(e:MouseEvent):void {
    if (gameSelesai) return;

    var skorLevelIni:int = 0;
    var kunciSekarang:Object = semuaKunci[levelCTD]; // Gunakan levelCTD

    for (var m:int = 1; m <= 4; m++) {
        var kiri:MovieClip = this["btnkiri" + m] as MovieClip;
        if (kiri.connectedTo != null) {
            if (kiri.connectedTo == kunciSekarang[kiri.name]) {
                skorLevelIni += 25; 
            }
        }
    }

    skorTotalGame += skorLevelIni; 
    txt_poinangka.text = String(skorTotalGame);

    // Logika Perpindahan yang Stabil
    if (levelCTD < 5) {
        levelCTD++; // Tambah angka level
        nextFrame(); // Pindah ke frame berikutnya dengan aman
    } else {
        timerGame.stop(); 
        timerGame.removeEventListener(TimerEvent.TIMER, hitungMundur);
        gotoAndStop(1, "DTB"); 
    }
}

// Panggil fungsi pertama kali
setupLevel();

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

stop();

import flash.events.MouseEvent;
import flash.display.MovieClip;

if (Object(this).skorTotalGame == undefined) {
    Object(this).skorTotalGame = 0; 
}

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;



// 1. DATABASE 5 LEVEL DTB
var dataLevelDTB:Array = [
    null,

    // LEVEL 1: Output Dasar 
    {
        soal: "#include &lt;iostream&gt;\nusing namespace std;\n\nint main() {\n  // Tampilkan teks ke layar\n  [ Zona 1 ] &lt;&lt; \"Halo, C++!\";\n  return 0;\n}",
        kunci: "btn_jawaban2", // Posisi 'cout' ada di tombol 2
        nilaiBlok: ["cin", "cout", "get", "print"] 
    },

    // LEVEL 2: Seleksi Tunggal (if)
    {
        soal: "int umur = 20;\n\n// Cek syarat minimal umur\n[ Zona 1 ] (umur >= 18) {\n  cout &lt;&lt; \"Boleh masuk\";\n}",
        kunci: "btn_jawaban1", // Posisi 'if' ada di tombol 1
        nilaiBlok: ["if", "else", "for", "switch"]
    },

    // LEVEL 3: Mencegah Fall-through pada Switch
    {
        soal: "char grade = 'A';\nswitch (grade) {\n  case 'A': \n    cout &lt;&lt; \"Sangat baik\"; \n    [ Zona 1 ]\n  case 'B': \n    cout &lt;&lt; \"Baik\";\n}",
        kunci: "btn_jawaban4", // Posisi 'break;' ada di tombol 4
        nilaiBlok: ["stop;", "exit;", "return;", "break;"]
    },

    // LEVEL 4: Perulangan Deterministik (for loop)
    {
        soal: "// Menampilkan angka 0 sampai 4\n[ Zona 1 ] (int i = 0; i &lt; 5; i++) {\n  cout &lt;&lt; i &lt;&lt; \" \";\n}",
        kunci: "btn_jawaban3", // Posisi 'for' ada di tombol 3
        nilaiBlok: ["while", "do", "for", "loop"]
    },

    // LEVEL 5: Post-test Loop (Minimal jalan 1 kali)
    {
        soal: "int x = 10;\ndo {\n  cout &lt;&lt; \"Nilai x: \" &lt;&lt; x;\n  x++;\n} [ Zona 1 ] (x &lt; 5);",
        kunci: "btn_jawaban2", // Posisi 'while' ada di tombol 2
        nilaiBlok: ["if", "while", "until", "for"]
    }
];

// Variabel Global untuk Interaksi
var soalAsli:String;
var jawabanBenarDTB:String;
var jawabanPemain:MovieClip;
var levelDTB:int = 1;

// --- TAMBAHAN VARIABEL GLOBAL UNTUK MENGUNCI KOORDINAT ---
var posisiAwalX:Array = [];
var posisiAwalY:Array = [];
var posisiTersimpan:Boolean = false;

// 2. FUNGSI SETUP LEVEL
function setupLevelDTB():void {
    jawabanPemain = null; 

    txt_poinangka.background = false; 
    txt_poinangka.border = false;
    // Ambil skor dari CTD dengan aman
    txt_poinangka.text = String(Object(this).skorTotalGame);

    // Gunakan levelDTB untuk menarik data
    var dataSekarang:Object = dataLevelDTB[levelDTB]; 
    soalAsli = dataSekarang.soal;
    jawabanBenarDTB = dataSekarang.kunci;
    txt_soal.htmlText = soalAsli;

    // Atur ulang balok-balok jawaban
    for (var j:int = 1; j <= 4; j++) {
        var btn:MovieClip = this["btn_jawaban" + j] as MovieClip;
        if (btn != null) {
            btn.buttonMode = true;

            // --- TANGAN BESI: KUNCI POSISI ---
            // Rekam posisi HANYA SATU KALI saat game pertama kali dimulai
            if (!posisiTersimpan) {
                posisiAwalX[j] = btn.x;
                posisiAwalY[j] = btn.y;
            }

            // Paksa balok pulang ke koordinat global yang sudah dikunci
            btn.x = posisiAwalX[j];
            btn.y = posisiAwalY[j];

            // Beri tahu mekanik drag & drop letak rumahnya yang mutlak
            btn.startX = posisiAwalX[j];
            btn.startY = posisiAwalY[j];
            // ---------------------------------

            // Beri nilai teks sesuai array di database
            btn.nilaiTeks = dataSekarang.nilaiBlok[j - 1]; 

            // Cegah event listener menumpuk
            btn.removeEventListener(MouseEvent.MOUSE_DOWN, ambilBlok);
            btn.removeEventListener(MouseEvent.MOUSE_UP, lepasBlok);
            btn.addEventListener(MouseEvent.MOUSE_DOWN, ambilBlok);
            btn.addEventListener(MouseEvent.MOUSE_UP, lepasBlok);
        }
    }

    posisiTersimpan = true; // Kunci agar Frame 2, 3, 4, 5 tidak ikut-ikutan merekam posisi

    btn_lanjutdtb.removeEventListener(MouseEvent.CLICK, cekSkorDTB);
    btn_lanjutdtb.addEventListener(MouseEvent.CLICK, cekSkorDTB);
}

// 3. MEKANIK DRAG
function ambilBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    setChildIndex(blok, numChildren - 1); 
    blok.startDrag();
}

// 4. MEKANIK DROP & WARNA MERAH
function lepasBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    blok.stopDrag();

    if (blok.hitTestObject(dropZone)) {
		dropZone.gotoAndStop(2);
        // Snap ke tengah dropZone
        blok.x = dropZone.x + (dropZone.width / 2) - (blok.width / 2);
        blok.y = dropZone.y + (dropZone.height / 2) - (blok.height / 2);

        jawabanPemain = blok; 

        // Ganti teks dengan string HTML Merah
        var teksMerah:String = "<font color='#FF0000'>" + blok.nilaiTeks + "</font>";
        txt_soal.htmlText = soalAsli.replace("[ Zona 1 ]", teksMerah);

        // Pulangkan balok lain
        for (var k:int = 1; k <= 4; k++) {
            var btnLain:MovieClip = this["btn_jawaban" + k] as MovieClip;
            if (btnLain != blok) {
                btnLain.x = btnLain.startX;
                btnLain.y = btnLain.startY;
            }
        }
    } else {
		dropZone.gotoAndStop(1);
        blok.x = blok.startX;
        blok.y = blok.startY;
        if (jawabanPemain == blok) {
            jawabanPemain = null; 
            txt_soal.htmlText = soalAsli; // Kembali polos
        }
    }
}

// 5. VALIDASI SKOR & LOGIKA PINDAH FRAME
function cekSkorDTB(e:MouseEvent):void {

    if (jawabanPemain != null) {
        if (jawabanPemain.name == jawabanBenarDTB) {
            Object(this).skorTotalGame += 25; 
            txt_poinangka.text = String(Object(this).skorTotalGame);
        }
    }

    // Logika Perpindahan yang Stabil
    if (levelDTB < 5) {
        levelDTB++; // Tambah angka level
        nextFrame(); // Geser ke frame berikutnya
    } else {
        gotoAndStop(1, "Skor"); // Tamat
    }
}

// Panggil setup saat Frame 1 dimulai
setupLevelDTB();
